const fmt = (v) => "R$ " + Number(v).toLocaleString("pt-BR",{minimumFractionDigits:2,maximumFractionDigits:2});
// Data local de hoje no formato YYYY-MM-DD (sem hora, sem conversão para UTC).
// Usar toISOString() aqui causava erro de fuso: à noite em UTC-3 a data "pulava"
// para o dia seguinte, fazendo contas serem classificadas como vencidas cedo demais.
const today = () => {
  const d = new Date();
  const mm = String(d.getMonth()+1).padStart(2,"0");
  const dd = String(d.getDate()).padStart(2,"0");
  return `${d.getFullYear()}-${mm}-${dd}`;
};
const addDays = (d,n) => { const dt=new Date(d); dt.setDate(dt.getDate()+n); return dt.toISOString().slice(0,10); };
// Soma n meses a uma data ISO (YYYY-MM-DD) sem problemas de fuso; ajusta o dia ao último dia do mês quando necessário.
const addMonths = (iso,n) => {
  const [y,m,d] = String(iso).split("-").map(Number);
  if (!y||!m||!d) return iso;
  const tot = (m-1)+n;
  const ny = y + Math.floor(tot/12);
  const nm = ((tot%12)+12)%12;
  const lastDay = new Date(ny, nm+1, 0).getDate();
  const nd = Math.min(d, lastDay);
  return `${ny}-${String(nm+1).padStart(2,"0")}-${String(nd).padStart(2,"0")}`;
};
const diffDays = (a) => { const d=new Date(a)-new Date(today()); return Math.round(d/86400000); };
const fmtDate = (iso) => { if(!iso) return ""; const [y,m,d]=iso.split("-"); return `${d}/${m}/${y}`; };

const EMPTY_BILL = { id:"", fornecedor:"", categoria:"Moradia", valor:"", vencimento:"", origem:"", obs:"", parcela:"", status:"pendente", pago_em:"" };

// Converte um "bill" do app para uma linha compatível com a tabela contas_pagar.
// Datas vazias precisam virar null (Postgres rejeita string vazia em coluna date)
// e os valores numéricos precisam ser Number.
const billToRow = (bill) => ({
  id: String(bill.id),
  fornecedor: bill.fornecedor || null,
  categoria: bill.categoria || null,
  valor: Number(bill.valor) || 0,
  vencimento: bill.vencimento || null,
  origem: bill.origem || null,
  obs: bill.obs || null,
  parcela: bill.parcela || null,
  status: bill.status || "pendente",
  pago_em: bill.pago_em || null,
  valor_pago: bill.valor_pago != null && bill.valor_pago !== "" ? Number(bill.valor_pago) : null,
});

// ─── STATUS helpers ──────────────────────────────────────────────────────────
function statusOf(bill) {
  if (bill.status === "pago") return "pago";
  // Comparação apenas por data (strings YYYY-MM-DD), sem hora nem fuso:
  // só é "vencido" se a data de vencimento for ANTERIOR a hoje (vencer hoje = pendente).
  if (bill.vencimento && bill.vencimento < today()) return "vencido";
  return "pendente";
}
